import{_ as r,o as a,c as n,ae as t}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Create In-App Sharing and Referral Links","description":"","frontmatter":{"title":"Create In-App Sharing and Referral Links","slug":"in-app-sharing-and-referral-links"},"headers":[],"relativePath":"marketer-hub/in-app-sharing-and-referral-links.md","filePath":"marketer-hub/in-app-sharing-and-referral-links.md"}'),i={name:"marketer-hub/in-app-sharing-and-referral-links.md"};function o(s,e,l,c,h,d){return a(),n("div",null,[...e[0]||(e[0]=[t('<p>Share links from the app to encourage installations and incentivize users for sharing. Branch enables you to trace connections to identify which users are bringing in others, and which shared materials are leading to the most installs and re-engagements.</p><h2 id="create-a-branchuniversalobject" tabindex="-1">Create a BranchUniversalObject <a class="header-anchor" href="#create-a-branchuniversalobject" aria-label="Permalink to &quot;Create a BranchUniversalObject&quot;">​</a></h2><p>A BranchUniversalObject (BUO) represents a unique piece of content, such as an article, video, or item for sale. Full code snippets for setting them up can be found here: <a href="./ios-full-reference.html#branch-universal-object">iOS</a>, <a href="./android-full-reference.html">Android</a>.</p><ul><li>Set a unique <code>canonicalIdentifier</code> for each piece of content.</li><li><code>canonicalUrl</code> should reflect the content’s web URL equivalent</li></ul><h2 id="set-the-link-s-properties" tabindex="-1">Set the link’s properties <a class="header-anchor" href="#set-the-link-s-properties" aria-label="Permalink to &quot;Set the link’s properties&quot;">​</a></h2><ul><li>Set redirect url in <code>$desktop_url</code> (mobile users will be sent to the platform-specific app store)</li><li>Set <code>feature</code> = “referrals”</li><li>[Optional] Customize link appearance by setting OG tags, though they will default to tags found in the web page set in <code>$desktop_url</code></li><li>[Optional] Set unique promo code in a key to reward the referred user</li></ul><p>Next, <strong>be sure to set the user ID of the referring user in a key such as</strong> <code>referringUserID</code><strong>.</strong> Then when a user clicks that link and opens the app, you can inspect <code>referringUserID</code> and connect the dots between referring and referred user. <strong>This is the fundamental piece required for you to measure which users are referring other users, and to reward them accordingly.</strong></p><h2 id="create-the-branch-link" tabindex="-1">Create the Branch Link <a class="header-anchor" href="#create-the-branch-link" aria-label="Permalink to &quot;Create the Branch Link&quot;">​</a></h2><p>Lastly, create the shortened Branch Link to be shared. Full code snippets on creating a Short Link using a BranchUniversalObject can be found here: <a href="./ios-full-reference.html">iOS</a>, <a href="./android-full-reference.html">Android</a>.</p><h2 id="use-webhooks-to-be-notified-when-shares-drive-conversions" tabindex="-1">Use webhooks to be notified when shares drive conversions <a class="header-anchor" href="#use-webhooks-to-be-notified-when-shares-drive-conversions" aria-label="Permalink to &quot;Use webhooks to be notified when shares drive conversions&quot;">​</a></h2><p>Customers with access to Branch&#39;s Advanced Data Feeds product can set up <a href="./webhooks.html">webhooks</a> to be notified of installs and conversions in real time.</p><ul><li>Filter for INSTALL (or conversion) events attributed to a <strong>feature = “referrals”</strong></li><li>The webhook can include the unique promo code and user ID (<code>referringUserID</code>) from the link you set up</li><li>After validating the promo code and <code>referringUserID</code>, you can reward the referring and/or referred user. You can manage credits in house or use a third-party system.</li></ul>',12)])])}const f=r(i,[["render",o]]);export{p as __pageData,f as default};
